// src/pages/contentCreator/ContentDashboard.js
import React from "react";
import Layout from "../../components/layout/Layout";

function ContentDashboard() {
  return (
    <Layout>
      <h1 className="mb-4" style={{ color: "#059669", fontWeight: "700" }}>
        Content Creator Dashboard
      </h1>

      <div className="card shadow-sm p-4" style={{ borderRadius: "12px" }}>
        <h5 className="card-title mb-3">Create and Manage Content</h5>
        <p>
          Here you can upload course materials, update existing content, and track
          content performance.
        </p>

        <button className="btn btn-success mt-3">Create New Content</button>
      </div>
    </Layout>
  );
}

export default ContentDashboard;
